import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is bandwidth?", a: "Bandwidth is the maximum rate of data transfer across a network connection, typically measured in Mbps (megabits per second) or Gbps (gigabits per second). Higher bandwidth allows faster data transfers and supports more simultaneous users." },
  { q: "How long does it take to download a 1 GB file?", a: "At 100 Mbps, a 1 GB file takes about 80 seconds. At 1 Gbps, it takes about 8 seconds. Use this calculator to find download time for any file size and connection speed." },
  { q: "What is the difference between Mbps and MB/s?", a: "Mbps (megabits per second) is used for network speed. MB/s (megabytes per second) is used for file transfer speed. There are 8 bits in a byte, so 100 Mbps = 12.5 MB/s." },
  { q: "How much bandwidth do I need?", a: "Streaming HD video needs ~5 Mbps, 4K needs ~25 Mbps. Video calls need ~3-4 Mbps. For multiple users and devices, add requirements together and add 20% buffer." },
  { q: "Why is my actual download speed lower than my plan's Mbps?", a: "ISP speeds are theoretical maximums. Real-world speeds are reduced by network congestion, Wi-Fi overhead (typically 20-30% loss vs. Ethernet), server upload speed limits, and the number of simultaneous users on your connection." },
  { q: "What is the difference between upload and download speed?", a: "Download speed is how fast data comes to your device. Upload speed is how fast data leaves your device. Most home internet plans are asymmetric - download speeds are much higher than upload. Fiber connections often offer symmetric speeds." },
  { q: "How much bandwidth does 4K video streaming require?", a: "Netflix recommends 25 Mbps for 4K Ultra HD. YouTube 4K uses 15-25 Mbps. If multiple people are streaming 4K simultaneously, you need to multiply accordingly - four 4K streams require approximately 100 Mbps." },
];

const SIZES = [{ label: "KB", factor: 1/1000 }, { label: "MB", factor: 1 }, { label: "GB", factor: 1000 }, { label: "TB", factor: 1000000 }];

export default function BandwidthCalculator() {
  const [fileSize, setFileSize] = useState(1000);
  const [sizeUnit, setSizeUnit] = useState("MB");
  const [speed, setSpeed] = useState(100);

  const sizeMB = fileSize * (SIZES.find(s => s.label === sizeUnit)?.factor || 1);
  const seconds = (sizeMB * 8) / speed;

  const fmt = (s: number) => s < 60 ? `${s.toFixed(1)} seconds` : s < 3600 ? `${(s/60).toFixed(1)} minutes` : `${(s/3600).toFixed(2)} hours`;

  return (
    <>
      <SEOHead
        title="Free Bandwidth Calculator Online - Calculate Download and Upload Time Instantly | CalcHive"
        description="Free online bandwidth calculator. Calculate download or upload time for any file size at any internet connection speed instantly. 100% free for everyone, no signup required."
        canonical="/bandwidth-calculator"
        keywords="free bandwidth calculator, download time calculator free online, upload time calculator free, file transfer time calculator free, internet speed bandwidth calculator free"
        category="Tech Tools"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-950/50 px-3 py-1 rounded-full mb-4 inline-block">Internet</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Bandwidth Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free bandwidth calculator to estimate download time or upload time from file size and internet speed. This download time calculator free online also works as an upload time calculator free, file transfer time calculator free, and internet speed bandwidth calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="file" label={`File Size (${sizeUnit})`} value={fileSize} min={1} max={10000} step={1} onChange={setFileSize} format={v => `${v} ${sizeUnit}`} testId="input-file" />
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">File Size Unit</label>
              <div className="flex gap-2">
                {SIZES.map(s => <button key={s.label} onClick={() => setSizeUnit(s.label)} className={`flex-1 py-2 rounded-xl text-sm font-semibold border transition-all ${sizeUnit === s.label ? "bg-blue-600 text-white border-blue-600" : "bg-card text-muted-foreground border-border hover:border-blue-400"}`}>{s.label}</button>)}
              </div>
            </div>
            <SliderInput id="speed" label="Connection Speed (Mbps)" value={speed} min={1} max={10000} step={1} onChange={setSpeed} format={v => v >= 1000 ? `${(v/1000).toFixed(1)} Gbps` : `${v} Mbps`} testId="input-speed" />
          </div>
          <motion.div key={`${fileSize}-${sizeUnit}-${speed}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-blue-500 to-blue-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Transfer Time</p>
              <p className="text-4xl font-black text-white tracking-tight" data-testid="result-time">{fmt(seconds)}</p>
              <p className="text-white/70 text-sm mt-1">{fileSize} {sizeUnit} at {speed} Mbps</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "MB/s Transfer Rate", value: `${(speed/8).toFixed(1)} MB/s` }, { label: "File Size (MB)", value: `${sizeMB.toFixed(2)} MB` }, { label: "File Size (GB)", value: `${(sizeMB/1000).toFixed(4)} GB` }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-sm font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Download and Upload Time for Any File for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Download time is the file size (converted to bits) divided by the connection speed in bits per second. The key conversion: 1 byte = 8 bits, so a 1 GB file is 8 gigabits of data.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>File Size in Megabits = File Size (MB)  x  8</p>
            <p>Transfer Time (seconds) = File Size (Megabits)  x  Speed (Mbps)</p>
            <p className="text-xs text-muted-foreground mt-2">Example: 1 GB file at 100 Mbps</p>
            <p>= (1,000 MB  x  8)  x  100 = 8,000  x  100 = 80 seconds</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Internet Speed Affects File Transfer Time</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["File Size", "10 Mbps", "100 Mbps", "1 Gbps"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["1 MB", "0.8 sec", "0.08 sec", "0.008 sec"],
                  ["100 MB", "80 sec", "8 sec", "0.8 sec"],
                  ["1 GB", "13.3 min", "80 sec", "8 sec"],
                  ["5 GB (movie)", "66.7 min", "6.7 min", "40 sec"],
                  ["25 GB (game)", "5.6 hrs", "33.3 min", "3.3 min"],
                  ["100 GB", "22.2 hrs", "2.2 hrs", "13.3 min"],
                  ["1 TB", "9.3 days", "22.2 hrs", "2.2 hrs"],
                ].map(([size, ...cells]) => (
                  <tr key={size} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{size}</td>
                    {cells.map((c, i) => <td key={i} className="py-2.5 px-4 text-muted-foreground">{c}</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Internet Speed and Bandwidth Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Activity", "Minimum", "Recommended", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["SD Video Streaming", "1 Mbps", "3 Mbps", "Netflix, YouTube 480p"],
                  ["HD Video Streaming", "3 Mbps", "5 Mbps", "1080p on Netflix"],
                  ["4K Video Streaming", "15 Mbps", "25 Mbps", "Netflix Ultra HD"],
                  ["Video Calls (HD)", "1.5 Mbps", "3 Mbps", "Zoom, Teams 1080p"],
                  ["Online Gaming", "3 Mbps", "25 Mbps", "Latency matters more than speed"],
                  ["Cloud Backup", "25 Mbps", "100+ Mbps", "Upload speed is the bottleneck"],
                  ["Remote Work / VPN", "10 Mbps", "25 Mbps", "File sharing, video calls"],
                ].map(([activity, min, rec, notes]) => (
                  <tr key={activity} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{activity}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{min}</td>
                    <td className="py-2.5 px-4 text-blue-600 dark:text-blue-400 font-medium">{rec}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h3 className="text-2xl font-bold text-foreground">Tips for Faster File Transfers</h3>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li>Use Ethernet instead of Wi-Fi - wired connections eliminate wireless overhead and typically deliver full plan speeds.</li>
            <li>Transfer files early morning or late night when ISP network congestion is lowest.</li>
            <li>Compress large files before transferring - tools like 7-Zip can reduce file sizes by 30-70% for compatible formats.</li>
            <li>Use transfer acceleration services like AWS S3 Transfer Acceleration or Cloudflare for cross-continental transfers.</li>
            <li>For local network transfers (NAS, PC-to-PC), Gigabit Ethernet delivers 1 Gbps theoretical speed - far faster than most internet connections.</li>
          </ul>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/bandwidth-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


